import json
import re
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)

# Elasticsearch client configuration
es = Elasticsearch(
    hosts=[{"host": "localhost", "port": 9200}],
    timeout=30,
)

# Allowlist of safe aggregation types
ALLOWED_AGG_TYPES = {"sum", "avg", "min", "max", "value_count", "cardinality", "stats", "extended_stats"}

# Allowlist of safe script languages
ALLOWED_LANGUAGES = {"painless"}

# Pattern to detect dangerous operations in Painless scripts
DANGEROUS_PATTERNS = [
    r"Runtime\s*\.",
    r"ProcessBuilder",
    r"getRuntime",
    r"exec\s*\(",
    r"System\s*\.\s*exit",
    r"java\s*\.\s*lang\s*\.\s*Runtime",
    r"java\s*\.\s*io\s*\.",
    r"java\s*\.\s*net\s*\.",
    r"java\s*\.\s*nio\s*\.",
    r"Thread\s*\.",
    r"ClassLoader",
    r"forName\s*\(",
    r"getClass\s*\(",
    r"newInstance\s*\(",
    r"invoke\s*\(",
    r"getDeclaredMethod",
    r"getDeclaredField",
    r"setAccessible",
    r"java\s*\.\s*lang\s*\.\s*reflect",
    r"ProcessBuilder",
    r"URLClassLoader",
    r"ScriptEngine",
    r"GroovyShell",
    r"MethodHandle",
    r"Unsafe",
]

# Allowed field name pattern (alphanumeric, underscores, dots)
FIELD_NAME_PATTERN = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_.]*$")

# Allowed index name pattern
INDEX_NAME_PATTERN = re.compile(r"^[a-zA-Z0-9_\-.*]+$")


def validate_script(script_source):
    """Validate that a Painless script does not contain dangerous operations."""
    if not isinstance(script_source, str):
        return False, "Script source must be a string"

    if len(script_source) > 500:
        return False, "Script source exceeds maximum length of 500 characters"

    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, script_source, re.IGNORECASE):
            return False, f"Script contains disallowed pattern: {pattern}"

    return True, "Script is valid"


def validate_field_name(field_name):
    """Validate that a field name is safe."""
    if not isinstance(field_name, str):
        return False
    if len(field_name) > 256:
        return False
    return bool(FIELD_NAME_PATTERN.match(field_name))


def validate_index_name(index_name):
    """Validate that an index name is safe."""
    if not isinstance(index_name, str):
        return False
    if len(index_name) > 256:
        return False
    if ".." in index_name:
        return False
    return bool(INDEX_NAME_PATTERN.match(index_name))


def validate_params(params):
    """Validate script parameters - only allow primitive types."""
    if params is None:
        return True, "No params"
    if not isinstance(params, dict):
        return False, "Params must be a dictionary"
    if len(params) > 20:
        return False, "Too many parameters"
    for key, value in params.items():
        if not isinstance(key, str) or len(key) > 64:
            return False, f"Invalid parameter key: {key}"
        if not isinstance(value, (int, float, str, bool)):
            return False, f"Parameter '{key}' must be a primitive type (int, float, str, bool)"
        if isinstance(value, str) and len(value) > 256:
            return False, f"Parameter '{key}' string value too long"
    return True, "Params are valid"


def build_predefined_aggregation(agg_name, agg_config):
    """Build a predefined (non-scripted) aggregation safely."""
    agg_type = agg_config.get("type")
    field = agg_config.get("field")

    if agg_type not in ALLOWED_AGG_TYPES:
        return None, f"Aggregation type '{agg_type}' is not allowed"

    if not validate_field_name(field):
        return None, f"Invalid field name: {field}"

    return {agg_type: {"field": field}}, None


def build_scripted_aggregation(agg_name, agg_config):
    """Build a scripted aggregation with thorough validation."""
    agg_type = agg_config.get("type")
    script_source = agg_config.get("script")
    script_lang = agg_config.get("lang", "painless")
    script_params = agg_config.get("params")

    # Validate aggregation type
    if agg_type not in ALLOWED_AGG_TYPES:
        return None, f"Aggregation type '{agg_type}' is not allowed. Allowed: {ALLOWED_AGG_TYPES}"

    # Validate script language
    if script_lang not in ALLOWED_LANGUAGES:
        return None, f"Script language '{script_lang}' is not allowed. Allowed: {ALLOWED_LANGUAGES}"

    # Validate script source
    is_valid, message = validate_script(script_source)
    if not is_valid:
        return None, f"Script validation failed: {message}"

    # Validate params
    is_valid, message = validate_params(script_params)
    if not is_valid:
        return None, f"Params validation failed: {message}"

    # Build the aggregation using stored script or inline with Painless only
    script_body = {
        "lang": script_lang,
        "source": script_source,
    }
    if script_params:
        script_body["params"] = script_params

    return {agg_type: {"script": script_body}}, None


@app.route("/api/aggregate", methods=["POST"])
def run_aggregation():
    """
    Execute an Elasticsearch aggregation with optional scripting.

    Expected JSON body:
    {
        "index": "my-index",
        "aggregations": {
            "my_agg": {
                "type": "sum",
                "script": "doc['price'].value * params.factor",
                "lang": "painless",
                "params": {"factor": 1.2}
            }
        },
        "query": {  // optional
            "match_all": {}
        },
        "size": 0  // optional, defaults to 0
    }

    Or without scripts (field-based):
    {
        "index": "my-index",
        "aggregations": {
            "avg_price": {
                "type": "avg",
                "field": "price"
            }
        }
    }
    """
    try:
        req_data = request.get_json()
        if not req_data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        # Validate index
        index = req_data.get("index")
        if not index or not validate_index_name(index):
            return jsonify({"error": "Invalid or missing index name"}), 400

        # Validate aggregations
        aggregations = req_data.get("aggregations")
        if not aggregations or not isinstance(aggregations, dict):
            return jsonify({"error": "Missing or invalid 'aggregations' field"}), 400

        if len(aggregations) > 10:
            return jsonify({"error": "Too many aggregations (max 10)"}), 400

        # Build aggregations
        es_aggs = {}
        for agg_name, agg_config in aggregations.items():
            if not isinstance(agg_name, str) or len(agg_name) > 64:
                return jsonify({"error": f"Invalid aggregation name: {agg_name}"}), 400

            if not isinstance(agg_config, dict):
                return jsonify({"error": f"Aggregation '{agg_name}' config must be a dictionary"}), 400

            if "script" in agg_config:
                agg_body, error = build_scripted_aggregation(agg_name, agg_config)
            elif "field" in agg_config:
                agg_body, error = build_predefined_aggregation(agg_name, agg_config)
            else:
                return jsonify({"error": f"Aggregation '{agg_name}' must have either 'script' or 'field'"}), 400

            if error:
                return jsonify({"error": error}), 400

            es_aggs[agg_name] = agg_body

        # Build the search body
        search_body = {
            "size": min(int(req_data.get("size", 0)), 100),
            "aggs": es_aggs,
        }

        # Optional query filter (only allow match_all, term, range, bool for safety)
        query = req_data.get("query")
        if query:
            if not isinstance(query, dict):
                return jsonify({"error": "Query must be a dictionary"}), 400
            # Only allow safe query types
            allowed_query_types = {"match_all", "term", "terms", "range", "bool", "match", "exists"}
            query_keys = set(query.keys())
            if not query_keys.issubset(allowed_query_types):
                disallowed = query_keys - allowed_query_types
                return jsonify({"error": f"Disallowed query types: {disallowed}"}), 400
            search_body["query"] = query

        # Execute the search
        result = es.search(index=index, body=search_body)

        # Extract and return aggregation results
        response = {
            "took": result.get("took"),
            "total_hits": result.get("hits", {}).get("total", {}).get("value", 0),
            "aggregations": result.get("aggregations", {}),
        }

        return jsonify(response), 200

    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON in request body"}), 400
    except Exception as e:
        # Don't leak internal details
        app.logger.error(f"Aggregation error: {str(e)}")
        return jsonify({"error": "An error occurred processing the aggregation request"}), 500


@app.route("/api/stored-script", methods=["POST"])
def create_stored_script():
    """
    Create a stored script in Elasticsearch (preferred over inline for reuse).

    Expected JSON body:
    {
        "script_id": "calculate_revenue",
        "script": "doc['price'].value * doc['quantity'].value",
        "lang": "painless",
        "description": "Calculate revenue from price and quantity"
    }
    """
    try:
        req_data = request.get_json()
        if not req_data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        script_id = req_data.get("script_id")
        if not script_id or not re.match(r"^[a-zA-Z_][a-zA-Z0-9_]{0,63}$", script_id):
            return jsonify({"error": "Invalid script_id. Use alphanumeric and underscores only."}), 400

        script_source = req_data.get("script")
        script_lang = req_data.get("lang", "painless")
        description = req_data.get("description", "")

        if script_lang not in ALLOWED_LANGUAGES:
            return jsonify({"error": f"Language '{script_lang}' not allowed"}), 400

        is_valid, message = validate_script(script_source)
        if not is_valid:
            return jsonify({"error": f"Script validation failed: {message}"}), 400

        if description and (not isinstance(description, str) or len(description) > 256):
            return jsonify({"error": "Description must be a string of max 256 characters"}), 400

        # Store the script
        body = {
            "script": {
                "lang": script_lang,
                "source": script_source,
            }
        }

        result = es.put_script(id=script_id, body=body)

        return jsonify({"status": "stored", "script_id": script_id, "acknowledged": result.get("acknowledged")}), 201

    except Exception as e:
        app.logger.error(f"Stored script error: {str(e)}")
        return jsonify({"error": "An error occurred storing the script"}), 500


